@strawberry.type
class Product:
    id: int
    name: str
    description: Optional[str]
    price: float
    seller_id: Optional[int]
    reviews: List[Review]
    categories: List[Category]
    images: List[Image]
    seller: Optional[Seller]

    @strawberry.field
    def average_rating(self) -> Optional[float]:
        if not self.reviews:
            return None
        return sum(r.rating for r in self.reviews) / len(self.reviews)

    @strawberry.field
    def review_count(self) -> int:
        return len(self.reviews)


# Helper functions to convert models to types
def _review_model_to_type(model: ReviewModel) -> Review:
    return Review(
        id=model.id,
        product_id=model.product_id,
        reviewer_name=model.reviewer_name,
        rating=model.rating,
        comment=model.comment,
    )


def _image_model_to_type(model: ImageModel) -> Image:
    return Image(
        id=model.id,
        product_id=model.product_id,
        url=model.url,
        alt_text=model.alt_text,
        is_primary=bool(model.is_primary),
    )


def _category_model_to_type(model: CategoryModel) -> Category:
    return Category(
        id=model.id,
        name=model.name,
        description=model.description,
    )


def _seller_model_to_type(model: SellerModel) -> Seller:
    return Seller(
        id=model.id,
        name=model.name,
        email=model.email,
        rating=model.rating,
    )


def _product_model_to_type(model: ProductModel) -> Product:
    return Product(
        id=model.id,
        name=model.name,
        description=model.description,
        price=model.price,
        seller_id=model.seller_id,
        reviews=[_review_model_to_type(r) for r in model.reviews],
        categories=[_category_model_to_type(c) for c in model.categories],
        images=[_image_model_to_type(i) for i in model.images],
        seller=_seller_model_to_type(model.seller) if model.seller else None,
    )


def _get_products_query(db: Session):
    return db.query(ProductModel).options(
        joinedload(ProductModel.seller),
        joinedload(ProductModel.reviews),
        joinedload(ProductModel.categories),
        joinedload(ProductModel.images),
    )


