# Query
@strawberry.type
class Query:
    @strawberry.field
    def products(
        self,
        info: Info,
        limit: Optional[int] = None,
        offset: Optional[int] = None,
        min_price: Optional[float] = None,
        max_price: Optional[float] = None,
        category_id: Optional[int] = None,
        seller_id: Optional[int] = None,
        search: Optional[str] = None,
    ) -> List[Product]:
        db: Session = info.context["db"]
        query = _get_products_query(db)

        if min_price is not None:
            query = query.filter(ProductModel.price >= min_price)
        if max_price is not None:
            query = query.filter(ProductModel.price <= max_price)
        if category_id is not None:
            query = query.filter(ProductModel.categories.any(CategoryModel.id == category_id))
        if seller_id is not None:
            query = query.filter(ProductModel.seller_id == seller_id)
        if search is not None:
            query = query.filter(
                ProductModel.name.ilike(f"%{search}%")
                | ProductModel.description.ilike(f"%{search}%")
            )
        if offset is not None:
            query = query.offset(offset)
        if limit is not None:
            query = query.limit(limit)

        products = query.all()
        return [_product_model_to_type(p) for p in products]

    @strawberry.field
    def product(self, info: Info, id: int) -> Optional[Product]:
        db: Session = info.context["db"]
        product = _get_products_query(db).filter(ProductModel.id == id).first()
        if not product:
            return None
        return _product_model_to_type(product)

    @strawberry.field
    def sellers(self, info: Info) -> List[Seller]:
        db: Session = info.context["db"]
        sellers = db.query(SellerModel).all()
        return [_seller_model_to_type(s) for s in sellers]

    @strawberry.field
    def seller(self, info: Info, id: int) -> Optional[Seller]:
        db: Session = info.context["db"]
        seller = db.query(SellerModel).filter(SellerModel.id == id).first()
        if not seller:
            return None
        return _seller_model_to_type(seller)

    @strawberry.field
    def categories(self, info: Info) -> List[Category]:
        db: Session = info.context["db"]
        categories = db.query(CategoryModel).all()
        return [_category_model_to_type(c) for c in categories]

    @strawberry.field
    def category(self, info: Info, id: int) -> Optional[Category]:
        db: Session = info.context["db"]
        category = db.query(CategoryModel).filter(CategoryModel.id == id).first()
        if not category:
            return None
        return _category_model_to_type(category)

    @strawberry.field
    def reviews(self, info: Info, product_id: Optional[int] = None) -> List[Review]:
        db: Session = info.context["db"]
        query = db.query(ReviewModel)
        if product_id is not None:
            query = query.filter(ReviewModel.product_id == product_id)
        reviews = query.all()
        return [_review_model_to_type(r) for r in reviews]

    @strawberry.field
    def images(self, info: Info, product_id: Optional[int] = None) -> List[Image]:
        db: Session = info.context["db"]
        query = db.query(ImageModel)
        if product_id is not None:
            query = query.filter(ImageModel.product_id == product_id)
        images = query.all()
        return [_image_model_to_type(i) for i in images]


# Mutation
@strawberry.type
class Mutation:
    @strawberry.mutation
    def create_product(self, info: Info, input: ProductInput) -> Product:
        db: Session = info.context["db"]
        product = ProductModel(
            name=input.name,
            description=input.description,
            price=input.price,
            seller_id=input.seller_id,
        )
        if input.category_ids:
            categories = db.query(CategoryModel).filter(
                CategoryModel.id.in_(input.category_ids)
            ).all()
            product.categories = categories
        db.add(product)
        db.commit()
        db.refresh(product)
        # Re-query with eager loading
        product = _get_products_query(db).filter(ProductModel.id == product.id).first()
        return _product_model_to_type(product)

    @strawberry.mutation
    def update_product(self, info: Info, id: int, input: ProductUpdateInput) -> Optional[Product]:
        db: Session = info.context["db"]
        product = db.query(ProductModel).filter(ProductModel.id == id).first()
        if not product:
            return None
        if input.name is not None:
            product.name = input.name
        if input.description is not None:
            product.description = input.description
        if input.price is not None:
            product.price = input.price
        if input.seller_id is not None:
            product.seller_id = input.seller_id
        if input.category_ids is not None:
            categories = db.query(CategoryModel).filter(
                CategoryModel.id.in_(input.category_ids)
            ).all()
            product.categories = categories
        db.commit()
        product = _get_products_query(db).filter(ProductModel.id == id).first()
        return _product_model_to_type(product)

    @strawberry.mutation
    def delete_product(self, info: Info, id: int) -> bool:
        db: Session = info.context["db"]
        product = db.query(ProductModel).filter(ProductModel.id == id).first()
        if not product:
            return False
        db.delete(product)
        db.commit()
        return True

    @strawberry.mutation
    def create_seller(self, info: Info, input: SellerInput) -> Seller:
        db: Session = info.context["db"]
        seller = SellerModel(
            name=input.name,
            email=input.email,
            rating=input.rating,
        )
        db.add(seller)
        db.commit()
        db.refresh(seller)
        return _seller_model_to_type(seller)

    @strawberry.mutation
    def create_category(self, info: Info, input: CategoryInput) -> Category:
        db: Session = info.context["db"]
        category = CategoryModel(
            name=input.name,
            description=input.description,
        )
        db.add(category)
        db.commit()
        db.refresh(category)
        return _category_model_to_type(category)

    @strawberry.mutation
    def create_review(self, info: Info, input: ReviewInput) -> Review:
        db: Session = info.context["db"]
        review = ReviewModel(
            product_id=input.product_id,
            reviewer_name=input.reviewer_name,
            rating=input.rating,
            comment=input.comment,
        )
        db.add(review)
        db.commit()
        db.refresh(review)
        return _review_model_to_type(review)

    @strawberry.mutation
    def create_image(self, info: Info, input: ImageInput) -> Image:
        db: Session = info.context["db"]
        image = ImageModel(
            product_id=input.product_id,
            url=input.url,
            alt_text=input.alt_text,
            is_primary=int(input.is_primary),
        )
        db.add(image)
        db.commit()
        db.refresh(image)
        return _image_model_to_type(image)


def get_context():
    db = SessionLocal()
    return {"db": db}


schema = strawberry.Schema(query=Query, mutation=Mutation)


